import {DECREMENT, INCREMENT} from '../types'

export default function (initialState = 5, action) {
    switch (action.type) {
        case INCREMENT:
            return initialState + 1
        case DECREMENT:
            return initialState - 1
        default:
            return initialState
    }
}
